import { describe, expect, it } from 'vitest';
import { assertGoldenPngEquals } from './helpers/golden-png-snapshot';
import { rgbFloat01InterleavedToPngBuffer } from './helpers/rgb-float01-to-png';
import { styleTransferAnyImage } from '../src/style-transfer-any-image';
function makePlane(w: number, h: number, seed: number): Float32Array {
  const out = new Float32Array(w * h * 3);
  let s = seed >>> 0;
  const rand = () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
  for (let i = 0; i < out.length; i++) out[i] = rand();
  return out;
}

const alphaWaveOff = { enabled: false, edgeThreshold: 0.22, edgeBoost: 0.7, frequency: 2.2, phase: 0 };

describe('style transfer golden PNG snapshots', () => {
  it('classical no mesh (16×16) matches golden bytes', async () => {
    const w = 16;
    const h = 16;
    const content = makePlane(w, h, 7);
    const style = makePlane(w, h, 8);
    const result = await styleTransferAnyImage(
      { data: content, width: w, height: h, channels: 3 },
      { data: style, width: w, height: h, channels: 3 },
      { method: 'classical', strength: 0.72, structurePreservation: 0.4, alphaWave: false },
    );
    const png = rgbFloat01InterleavedToPngBuffer(result.stylized, w, h);
    assertGoldenPngEquals(png, 'classical-no-mesh-16');
  });

  it('classical mesh stub topology (16×16) matches golden bytes', async () => {
    const w = 16;
    const h = 16;
    const content = makePlane(w, h, 7);
    const style = makePlane(w, h, 8);
    const result = await styleTransferAnyImage(
      { data: content, width: w, height: h, channels: 3 },
      { data: style, width: w, height: h, channels: 3 },
      {
        method: 'classical',
        strength: 0.72,
        structurePreservation: 0.4,
        alphaWave: false,
        meshGate: { enabled: true },
      },
    );
    const png = rgbFloat01InterleavedToPngBuffer(result.stylized, w, h);
    assertGoldenPngEquals(png, 'classical-mesh-stub-16');
  });

  it('classical mesh + depth confidence (16×16) matches golden bytes', async () => {
    const w = 16;
    const h = 16;
    const n = w * h;
    const content = makePlane(w, h, 7);
    const style = makePlane(w, h, 8);
    const depthConfidence = new Float32Array(n);
    depthConfidence.fill(0.55);
    const result = await styleTransferAnyImage(
      { data: content, width: w, height: h, channels: 3 },
      { data: style, width: w, height: h, channels: 3 },
      {
        method: 'classical',
        strength: 0.72,
        structurePreservation: 0.4,
        alphaWave: false,
        meshGate: { enabled: true, depthConfidence },
      },
    );
    const png = rgbFloat01InterleavedToPngBuffer(result.stylized, w, h);
    assertGoldenPngEquals(png, 'classical-mesh-depth-16');
  });

  it('rgbFloat01InterleavedToPngBuffer rejects wrong length', () => {
    expect(() => rgbFloat01InterleavedToPngBuffer(new Float32Array(10), 4, 4)).toThrow(RangeError);
  });
});
